public boolean canBalance(int[] nums)
{
    double sum = 0;
    for (int n : nums) {
        sum += n;
    }

    double target = sum / 2;
    sum = 0;

    for (int i : nums) {
        sum += i;
        if (sum == target) {
            return true;
        }
    }
    return false;
}

public boolean isEverywhere(int[] nums, int val)
{
