public int blackjack(int a, int b)
{
    if ((a < 21) && (b < 21))
        return a > b ? a : b;
    else if (a > 21)
        return b;
    else if (b > 21)
        return a;
    return 0;
}

public int[] tenRun(int[] nums)
{
    int[] result = new int[nums.length];
    int input;
    int value = -1;

    for (int i = 0; i < nums.length; i++)
    {
        input = nums[i];

        if (input % 10 == 0 && input > value)
        {
            value = input;
        }

        if (value == -1)
        {
            result[i] = input;
        }
        else
        {
            result[i] = value;
        }
    }

    return result;
}

public int centeredAverage(int[] nums)
{
     nums.sort();
     int count = 0;
     int sum = 0;
     for (int i = 1; i < nums.length - 1; i++){
     sum += nums[i];
     count++;}
     return sum / count;
}

